const tumGirdiler = $input.all();

const kriptoMap = {};
const borsaGirdileri = [];

// Gelen tüm verileri yapılarına göre otomatik ayrıştırıyoruz
for (const girdi of tumGirdiler) {
  const data = girdi.json;

  if (data.symbol && data.lastPrice !== undefined) {
    kriptoMap[data.symbol] = {
      price: parseFloat(data.lastPrice || 0),
      change: parseFloat(data.priceChangePercent || 0)
    };
  }

  if (data.chart && data.chart.result) {
    borsaGirdileri.push(data);
  }
}

// HTML E-posta Tablosunun Başlangıcı ve Tasarımı
let html = `
<table border="1" cellpadding="8" style="border-collapse: collapse; font-family: Arial, sans-serif; width: 100%; max-width: 650px; border: 1px solid #ddd;">
  <thead>
    <tr style="background-color: #f2f2f2; text-align: left;">
      <th style="border: 1px solid #ddd;">Varlık Adı</th>
      <th style="border: 1px solid #ddd;">Son Fiyat</th>
      <th style="border: 1px solid #ddd;">Günlük (24s)</th>
      <th style="border: 1px solid #ddd;">Haftalık (7g)</th>
      <th style="border: 1px solid #ddd;">Aylık (30g)</th>
    </tr>
  </thead>
  <tbody>
`;

// Yapay zekaya gönderilecek temiz veri metni
let aiGirdisi = "BUGÜNKÜ FİNANS PİYASASI VERİLERİ:\n\n";

// Değişim yüzdelerini şık yeşil/kırmızı oklara çeviren yardımcı fonksiyon
function formatSpan(val) {
  if (val === null || val === undefined) return `<span style="color: #999;">-</span>`;
  const renk = val >= 0 ? "green" : "red";
  const ok = val >= 0 ? "▲ +" : "▼ ";
  return `<span style="color: ${renk}; font-weight: bold;">${ok}${val.toFixed(2)}%</span>`;
}

// Tabloya satır ekleme fonksiyonu
function tabloSatiriEkle(isim, sayiFiyat, sayiDegisimGunluk, sayiDegisimHaftalik, sayiDegisimAylik, birim) {
  let formatliFiyat = "";
  if (birim === "USD") {
    formatliFiyat = "$" + sayiFiyat.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  } else if (birim === "TL") {
    formatliFiyat = sayiFiyat.toLocaleString('tr-TR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + " TL";
  }

  return `
    <tr>
      <td style="border: 1px solid #ddd;"><b>${isim}</b></td>
      <td style="border: 1px solid #ddd; font-weight: bold;">${formatliFiyat}</td>
      <td style="border: 1px solid #ddd;">${formatSpan(sayiDegisimGunluk)}</td>
      <td style="border: 1px solid #ddd;">${formatSpan(sayiDegisimHaftalik)}</td>
      <td style="border: 1px solid #ddd;">${formatSpan(sayiDegisimAylik)}</td>
    </tr>
  `;
}

// --- 1. KRİPTO PARALAR (USD) ---
if (kriptoMap["BTCUSDT"]) {
  const p = kriptoMap["BTCUSDT"].price;
  const c = kriptoMap["BTCUSDT"].change;
  html += tabloSatiriEkle("Bitcoin (BTC)", p, c, null, null, "USD");
  aiGirdisi += `- Bitcoin: $${p.toFixed(2)} (Günlük: %${c.toFixed(2)})\n`;
}
if (kriptoMap["ETHUSDT"]) {
  const p = kriptoMap["ETHUSDT"].price;
  const c = kriptoMap["ETHUSDT"].change;
  html += tabloSatiriEkle("Ethereum (ETH)", p, c, null, null, "USD");
  aiGirdisi += `- Ethereum: $${p.toFixed(2)} (Günlük: %${c.toFixed(2)})\n`;
}
if (kriptoMap["SOLUSDT"]) {
  const p = kriptoMap["SOLUSDT"].price;
  const c = kriptoMap["SOLUSDT"].change;
  html += tabloSatiriEkle("Solana (SOL)", p, c, null, null, "USD");
  aiGirdisi += `- Solana: $${p.toFixed(2)} (Günlük: %${c.toFixed(2)})\n`;
}
if (kriptoMap["XRPUSDT"]) {
  const p = kriptoMap["XRPUSDT"].price;
  const c = kriptoMap["XRPUSDT"].change;
  html += tabloSatiriEkle("Ripple (XRP)", p, c, null, null, "USD");
  aiGirdisi += `- Ripple: $${p.toFixed(2)} (Günlük: %${c.toFixed(2)})\n`;
}

// --- 2. DÖVİZ VE ALTIN HESAPLAMALARI (TL) ---
let usdTryPrice = 1;
if (kriptoMap["USDTTRY"]) {
  usdTryPrice = kriptoMap["USDTTRY"].price;
  const c = kriptoMap["USDTTRY"].change;
  html += tabloSatiriEkle("Dolar (USD/TRY)", usdTryPrice, c, null, null, "TL");
  aiGirdisi += `- Dolar Kuru: ${usdTryPrice.toFixed(2)} TL (Günlük: %${c.toFixed(2)})\n`;
}

let gramAltinPrice = 0;
let altinChange = 0;
if (kriptoMap["PAXGUSDT"]) {
  const paxgUsd = kriptoMap["PAXGUSDT"].price;
  altinChange = kriptoMap["PAXGUSDT"].change;
  gramAltinPrice = (paxgUsd * usdTryPrice) / 31.1035;
  html += tabloSatiriEkle("Gram Altın", gramAltinPrice, altinChange, null, null, "TL");
  aiGirdisi += `- Gram Altın: ${gramAltinPrice.toFixed(2)} TL (Günlük: %${altinChange.toFixed(2)})\n`;
}

if (gramAltinPrice > 0) {
  const ceyrekAltinPrice = gramAltinPrice * 1.6065;
  html += tabloSatiriEkle("Çeyrek Altın", ceyrekAltinPrice, altinChange, null, null, "TL");
  aiGirdisi += `- Çeyrek Altın: ${ceyrekAltinPrice.toFixed(2)} TL\n`;
}

const borsaIsimleri = {
  "KCHOL.IS": "Koç Holding (KCHOL)",
  "ASELS.IS": "Aselsan (ASELS)",
  "TUPRS.IS": "Tüpraş (TUPRS)",
  "SAHOL.IS": "Sabancı Holding (SAHOL)",
  "AYGZ.IS": "Aygaz (AYGZ)",
  "FROTO.IS": "Ford Otosan (FROTO)"
};

// --- 3. BORSA İSTANBUL HİSSELERİ (TL) ---
for (const borsaData of borsaGirdileri) {
  if (borsaData.chart && borsaData.chart.result) {
    const result = borsaData.chart.result[0];
    const meta = result.meta;
    const symbol = meta.symbol;
    const price = meta.regularMarketPrice;

    const closes = result.indicators && result.indicators.quote && result.indicators.quote[0] && result.indicators.quote[0].close
      ? result.indicators.quote[0].close.filter(c => c !== null && c !== undefined)
      : [];

    let dailyChangePercent = 0;
    let weeklyChangePercent = 0;
    let monthlyChangePercent = 0;

    const prevDaily = meta.previousClose || (closes.length >= 2 ? closes[closes.length - 2] : price);
    dailyChangePercent = prevDaily ? ((price - prevDaily) / prevDaily) * 100 : 0;

    const prevWeekly = closes.length >= 6 ? closes[closes.length - 6] : closes[0];
    weeklyChangePercent = prevWeekly ? ((price - prevWeekly) / prevWeekly) * 100 : 0;

    const prevMonthly = closes[0];
    monthlyChangePercent = prevMonthly ? ((price - prevMonthly) / prevMonthly) * 100 : 0;

    const isim = borsaIsimleri[symbol] || symbol;
    html += tabloSatiriEkle(isim, price, dailyChangePercent, weeklyChangePercent, monthlyChangePercent, "TL");

    aiGirdisi += `- ${isim}: ${price.toFixed(2)} TL (Günlük: %${dailyChangePercent.toFixed(2)}, Haftalık: %${weeklyChangePercent.toFixed(2)}, Aylık: %${monthlyChangePercent.toFixed(2)})\n`;
  }
}

html += `</tbody></table>`;
return [{ json: { mail_icerik: html, ai_girdisi: aiGirdisi } }];

// 1. Yapay zekanın ürettiği yorumu alıyoruz
const aiMetin = $input.first().json.choices?.[0]?.message?.content || "";

// 2. İlk JavaScript düğümünden gelen ana finans tablosunu çekiyoruz
const tabloMetin = $('Code in JavaScript').first().json.mail_icerik || "";

// 3. YENİ: IPO Hesaplayıcı düğümünden halka arz verilerini çekiyoruz
let ipoItems = [];
try {
  ipoItems = $('IPO Hesaplayıcı').all().map(item => item.json);
} catch (e) {
  ipoItems = [];
}

// 4. YENİ: Halka Arzlar için ayrı HTML Tablosu oluşturuyoruz
let ipoTabloMetin = "";

if (ipoItems.length > 0) {
  ipoTabloMetin = `
    <!-- Ayrı Halka Arz Performans Kartı -->
    <div style="margin-top: 25px; background-color: #ffffff; border: 1px solid #e1e8ed; border-radius: 6px; padding: 15px; font-family: Arial, sans-serif;">
      <span style="font-size: 16px; font-weight: bold; color: #2c3e50; display: block; margin-bottom: 12px; border-bottom: 2px solid #27ae60; padding-bottom: 6px;">
        🚀 Son 5 Halka Arz Performansı
      </span>
      <table style="width: 100%; border-collapse: collapse; font-size: 13px; text-align: left;">
        <thead>
          <tr style="background-color: #f8fafc; color: #475569;">
            <th style="padding: 8px; border-bottom: 1px solid #e2e8f0;">Şirket</th>
            <th style="padding: 8px; border-bottom: 1px solid #e2e8f0;">Son Fiyat</th>
            <th style="padding: 8px; border-bottom: 1px solid #e2e8f0;">Günlük</th>
            <th style="padding: 8px; border-bottom: 1px solid #e2e8f0;">Haftalık</th>
            <th style="padding: 8px; border-bottom: 1px solid #e2e8f0;">Toplam Getiri</th>
          </tr>
        </thead>
        <tbody>
  `;

  ipoItems.forEach(ipo => {
    const dailyColor = ipo.dailyChange >= 0 ? '#27ae60' : '#e74c3c';
    const weeklyColor = ipo.weeklyChange >= 0 ? '#27ae60' : '#e74c3c';
    const totalColor = ipo.totalReturn >= 0 ? '#27ae60' : '#e74c3c';

    const dailySign = ipo.dailyChange > 0 ? '+' : '';
    const weeklySign = ipo.weeklyChange > 0 ? '+' : '';
    const totalSign = ipo.totalReturn > 0 ? '+' : '';

    ipoTabloMetin += `
      <tr style="border-bottom: 1px solid #f1f5f9;">
        <td style="padding: 8px; color: #1e293b;"><b>${ipo.name}</b> (${ipo.symbol})</td>
        <td style="padding: 8px; color: #1e293b;">₺${ipo.currentPrice}</td>
        <td style="padding: 8px; color: ${dailyColor}; font-weight: bold;">%${dailySign}${ipo.dailyChange}</td>
        <td style="padding: 8px; color: ${weeklyColor}; font-weight: bold;">%${weeklySign}${ipo.weeklyChange}</td>
        <td style="padding: 8px; color: ${totalColor}; font-weight: bold;">%${totalSign}${ipo.totalReturn}</td>
      </tr>
    `;
  });

  ipoTabloMetin += `
        </tbody>
      </table>
    </div>
  `;
}

// 5. Tüm parçaları (AI Raporu + Ana Finans Tablosu + Halka Arz Tablosu) şablonda birleştiriyoruz
let finalHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta http-equiv="Content-Type" content="text/html; charset=utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>
<body style="margin: 0; padding: 0; font-family: Arial, sans-serif; color: #333; background-color: #ffffff;">

  <div style="max-width: 650px; margin: 0 auto; padding: 10px;">

    <!-- Yapay Zeka Yorum Kutusu -->
    <div style="background-color: #f4f9f4; border-left: 4px solid #2ecc71; padding: 15px; margin-bottom: 25px; border-radius: 4px; line-height: 1.6;">
      <span style="font-size: 18px; font-weight: bold; color: #27ae60; display: block; margin-bottom: 12px;">🤖 Yapay Zeka Teknik Analiz Raporu</span>
      <p style="margin: 0; font-size: 14px; color: #2c3e50; white-space: pre-line; font-family: Arial, sans-serif; line-height: 1.6;">
        ${aiMetin}
      </p>
    </div>

    <!-- Ana Finans Tablosu -->
    ${tabloMetin}

    <!-- Son 5 Halka Arz Tablosu -->
    ${ipoTabloMetin}

  </div>

</body>
</html>
`;

// 6. Türkçe karakterleri asla bozulmayacak HTML Entity kodlarına dönüştürüyoruz
const safeHtml = finalHtml
  .replace(/ç/g, '&#231;')
  .replace(/Ç/g, '&#199;')
  .replace(/ğ/g, '&#287;')
  .replace(/Ğ/g, '&#286;')
  .replace(/ı/g, '&#305;')
  .replace(/İ/g, '&#304;')
  .replace(/ö/g, '&#246;')
  .replace(/Ö/g, '&#214;')
  .replace(/ş/g, '&#351;')
  .replace(/Ş/g, '&#350;')
  .replace(/ü/g, '&#252;')
  .replace(/Ü/g, '&#220;');

// 7. n8n çıktısı
return [{
  json: {
    html_body: safeHtml
  }
}];

const inputJson = $input.first().json;
let rawHtml = inputJson.data || inputJson.body || (typeof inputJson === 'string' ? inputJson : JSON.stringify(inputJson));

function fixTurkishText(str) {
  if (!str) return "";
  let text = str.replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&quot;/g, '"');
  const map = {
    '脟': 'Ç', 'Ã‡': 'Ç', '脧': 'Ç', '莽': 'ç', 'Ã§': 'ç',
    '脛臑': 'Ğ', 'ÄĞ': 'Ğ', '脛鸥': 'ğ', 'ÄŸ': 'ğ',
    '脛脛': 'İ', 'Ä°': 'İ', '陌': 'İ', '脛卤': 'ı', 'Ä±': 'ı', '谋': 'ı',
    '脰': 'Ö', 'Ã–': 'Ö', '枚': 'ö', 'Ã¶': 'ö',
    '艦': 'Ş', 'Åž': 'Ş', '艧': 'ş', 'ÅŸ': 'ş',
    '脺': 'Ü', 'Ãœ': 'Ü', '眉': 'ü', 'Ã¼': 'ü', 'ï¿½': ''
  };
  for (const [bad, good] of Object.entries(map)) {
    text = text.split(bad).join(good);
  }
  return text.trim();
}

const extractedIpos = [];
const seenSymbols = new Set();
const articleRegex = /<article[^>]*class=["'][^"']*index-list[^"']*["'][^>]*>(.*?)<\/article>/gis;

let match;

while ((match = articleRegex.exec(rawHtml)) !== null) {
  const blockHtml = match[1];

  // A. BIST Kodu
  const bistMatch = blockHtml.match(/class=["'][^"']*il-bist-kod[^"']*["'][^>]*>\s*([A-Z0-9]{3,6})\s*<\/span>/i);
  if (!bistMatch) continue;
  const symbol = bistMatch[1].trim();

  // B. Rozet Filtresi
  const hasNewClass = blockHtml.includes('il-new') || /class=["'][^"']*il-new[^"']*["']/i.test(blockHtml);
  const blockTextLower = blockHtml.toLowerCase();

  const isPending = hasNewClass || 
                    blockTextLower.includes('yeni!') || 
                    blockTextLower.includes('il-tt') || 
                    blockTextLower.includes('talep toplan') || 
                    blockTextLower.includes('taslak') || 
                    blockTextLower.includes('spk');

  if (isPending) continue;

  // C. Şirket Adı
  let companyName = "";
  const nameMatch = blockHtml.match(/class=["'][^"']*il-halka-arz-sirket[^"']*["'][^>]*>(.*?)<\/h3>/i);
  if (nameMatch) {
    companyName = nameMatch[1];
  } else {
    const titleAttrMatch = blockHtml.match(/title=["']([^"']+)["']/i);
    if (titleAttrMatch) companyName = titleAttrMatch[1];
  }
  companyName = fixTurkishText(companyName);

  // D. Detay Sayfası Linki
  const urlMatch = blockHtml.match(/href=["']([^"']+)["']/i);
  const url = urlMatch ? urlMatch[1] : "";

  if (symbol && !seenSymbols.has(symbol) && /^[A-Z0-9]{3,6}$/.test(symbol)) {
    seenSymbols.add(symbol);
    extractedIpos.push({
      symbol: `${symbol}.IS`,
      name: companyName || symbol,
      url: url,
      status: "İşlem Gören"
    });
  }

  if (extractedIpos.length === 5) break;
}

return extractedIpos.map(ipo => ({ json: ipo }));

const results = [];
const items = $input.all();

// 1. Detay sayfalarından (IPO Detay Fetch) orijinal halka arz fiyatlarını okuyoruz
const detailItems = $('IPO Detay Fetch').all();
const scraperItems = $('Halka Arz Kazıyıcı').all();

const infoMap = {};

scraperItems.forEach((scItem, idx) => {
  const symbol = scItem.json.symbol;
  const detailHtml = detailItems[idx]?.json?.data || detailItems[idx]?.json?.body || "";

  let ipoPrice = 0;
  const priceMatch = 
    detailHtml.match(/Halka\s*Arz\s*Fiyat[ıi\/]*[\s\S]*?<strong[^>]*>\s*([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)\s*<\/strong>/i) ||
    detailHtml.match(/<strong[^>]*class=["'][^"']*f700[^"']*["'][^>]*>\s*([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)\s*<\/strong>/i) ||
    detailHtml.match(/([0-9]{1,4}[.,][0-9]{2})\s*(?:TL|₺)/i);

  if (priceMatch) {
    ipoPrice = parseFloat(priceMatch[1].replace(/\./g, '').replace(',', '.'));
  }

  infoMap[symbol] = {
    name: scItem.json.name,
    ipoPrice: ipoPrice
  };
});

// 2. Yahoo Finance verileriyle kesin 5 iş günü hesaplaması yapıyoruz
for (const item of items) {
  const yahooData = item.json;
  const chartResult = yahooData.chart?.result?.[0];

  if (!chartResult) continue;

  const fullSymbol = chartResult.meta.symbol;
  const cleanSymbol = fullSymbol.replace('.IS', '');
  const companyInfo = infoMap[fullSymbol] || { name: cleanSymbol, ipoPrice: 0 };

  const rawQuotes = chartResult.indicators?.quote?.[0]?.close || [];
  const cleanQuotes = rawQuotes.filter(p => p !== null && p !== undefined);

  if (cleanQuotes.length === 0) continue;

  const currentPrice = chartResult.meta.regularMarketPrice || cleanQuotes[cleanQuotes.length - 1];

  // A. GÜNLÜK DEĞİŞİM (%) - BIST %10 Tavan/Taban Limitli
  let prevClose = cleanQuotes.length >= 2 ? cleanQuotes[cleanQuotes.length - 2] : (chartResult.meta.chartPreviousClose || currentPrice);
  let dailyChange = prevClose > 0 && prevClose !== currentPrice ? ((currentPrice - prevClose) / prevClose) * 100 : 0;

  if (dailyChange > 10) dailyChange = 10.00;
  if (dailyChange < -10) dailyChange = -10.00;

  // B. HAFTALIK DEĞİŞİM (%) - Kesin Olarak "Son 5 İş Günü" (5 Seans Önceki Kapanış vs Bugün)
  let weeklyChange = 0;
  if (cleanQuotes.length >= 6) {
    // Bugün (cleanQuotes.length - 1) ile TAM 5 İŞ GÜNÜ ÖNCEKİ (cleanQuotes.length - 6) kapanış karşılaştırılır
    const fiveTradingDaysAgoPrice = cleanQuotes[cleanQuotes.length - 6];
    weeklyChange = fiveTradingDaysAgoPrice > 0 ? ((currentPrice - fiveTradingDaysAgoPrice) / fiveTradingDaysAgoPrice) * 100 : 0;
  } else {
    // Eğer hisse henüz 5 iş gününden az süredir borsa ortamında işlem görüyorsa: İlk Borsa Günü Kapanışı -> Bugün
    const firstDayPrice = cleanQuotes[0];
    weeklyChange = firstDayPrice > 0 ? ((currentPrice - firstDayPrice) / firstDayPrice) * 100 : 0;
  }

  // C. TOPLAM GETİRİ (%): Orijinal Halka Arz Fiyatından (Örn: 70,00 TL) Hesaplama
  let totalReturn = 0;
  const basePrice = companyInfo.ipoPrice > 0 ? companyInfo.ipoPrice : cleanQuotes[0];
  if (basePrice > 0) {
    totalReturn = ((currentPrice - basePrice) / basePrice) * 100;
  }

  results.push({
    json: {
      symbol: cleanSymbol,
      name: companyInfo.name,
      ipoPrice: companyInfo.ipoPrice,
      currentPrice: Number(currentPrice.toFixed(2)),
      dailyChange: Number(dailyChange.toFixed(2)),
      weeklyChange: Number(weeklyChange.toFixed(2)),
      totalReturn: Number(totalReturn.toFixed(2)),
      tradingDays: cleanQuotes.length
    }
  });
}

return results;
